package escalation

import (
	"fmt"
	"strings"
	"sync"
)

// InfrastructureFailurePatterns are detail substrings that indicate a
// transient infrastructure-level failure (provider 502, network unreachable,
// command not found, auth/quota exhausted) rather than a model-capability
// failure (test failed, build failed, no changes after attempt).
//
// Infrastructure failures should not consume escalation budget — the bead
// should be deferred with a retry-after, not retried at the next tier with
// a more expensive model. The model wasn't given a fair chance.
//
// Patterns are matched case-insensitively as substrings of the failure
// detail string. Any new pattern added here is automatically picked up by
// IsInfrastructureFailure callers.
var InfrastructureFailurePatterns = []string{
	// HTTP-level provider unavailability
	"502", "503", "504",
	"bad gateway",
	"service unavailable",
	"gateway timeout",
	// Network-level unreachability
	"connection refused",
	"no such host",
	"no route to host",
	"network is unreachable",
	"i/o timeout",
	"context deadline exceeded",
	// Auth/quota exhaustion (operator-fixable, not a model fault)
	"401", "429",
	"unauthorized",
	"rate limit",
	"ratelimit",
	"quota exceeded",
	"insufficient quota",
	"insufficient_quota",
	// Subprocess harness binary missing or unstartable
	"command not found",
	"executable file not found",
	"no such file or directory",
}

// IsInfrastructureFailure reports whether the given failure status + detail
// indicates a transient infrastructure problem the model could not have
// fixed. Only execution_failed can be infrastructure; other escalatable
// statuses are semantic outcomes that should proceed through the tier ladder.
// Returns false for statuses whose detail does not match any known
// infrastructure pattern.
//
// Used by the execute-loop to decide whether to (a) defer the bead with a
// retry-after and try the same tier later, or (b) burn through to the next
// tier as the standard escalation policy.
func IsInfrastructureFailure(status, detail string) bool {
	if status != "execution_failed" {
		return false
	}
	if detail == "" {
		return false
	}
	lower := strings.ToLower(detail)
	for _, p := range InfrastructureFailurePatterns {
		if strings.Contains(lower, p) {
			return true
		}
	}
	return false
}

// DefaultMaxCostUSD is the per-execute-loop dollar cap on accumulated billed
// spend. Exceeding the cap halts further bead claiming so an execute-loop
// run cannot silently burn through arbitrary openrouter / pay-per-token
// credits. Local LLMs and subscription-bundled providers do not count
// toward the cap (see CountsTowardCostCap).
//
// $100 is large enough not to interrupt normal subscription-driven work
// (where billed cost stays at $0) and small enough to surface a clear stop
// signal before runaway openrouter usage.
const DefaultMaxCostUSD = 100.0

// CostClassBilled is the HarnessInfo.CostClass value the agent uses for
// pay-per-token providers. Free local providers report "free" and
// subscription-bundled providers report "subscription".
const CostClassBilled = "expensive"

// CountsTowardCostCap returns true when an attempt's reported CostUSD
// should accumulate against the loop's MaxCostUSD. Callers pass the
// HarnessInfo of the harness that ran the attempt; when info is nil the
// safe default is to count (treat unknown as billed).
func CountsTowardCostCap(isLocal, isSubscription bool, costClass string) bool {
	if isLocal {
		return false
	}
	if isSubscription {
		return false
	}
	// CostClass "free" or "subscription" never bill; only "expensive" does.
	if costClass != "" && costClass != CostClassBilled {
		return false
	}
	return true
}

// HarnessBilledLookup reports whether a harness's reported CostUSD should
// be accumulated against a CostCapTracker. Implementations typically
// consult a service.ListHarnesses snapshot. A nil lookup is treated as
// "count by default" (the safe option for unknown harnesses).
type HarnessBilledLookup func(harnessName string) bool

// CostCapTracker accumulates billed cost for a single execute-loop run
// and reports when accumulated spend has reached the configured cap.
// Safe for concurrent use across goroutines (workers may call Add and
// Tripped concurrently).
//
// MaxUSD == 0 disables the cap; Tripped always returns (_, false). The
// Lookup callback decides which harnesses contribute to the running
// total — local and subscription-bundled providers should be excluded
// (see CountsTowardCostCap).
type CostCapTracker struct {
	MaxUSD float64
	Lookup HarnessBilledLookup

	mu    sync.Mutex
	spent float64
	// cache memoizes Lookup results so we do not rebuild a service for
	// every reported attempt. Protected by mu.
	cache map[string]bool
}

// NewCostCapTracker constructs a tracker with the given dollar cap and
// lookup. Pass maxUSD <= 0 to disable the cap. A nil lookup is treated
// as "count by default" — every harness contributes.
func NewCostCapTracker(maxUSD float64, lookup HarnessBilledLookup) *CostCapTracker {
	return &CostCapTracker{
		MaxUSD: maxUSD,
		Lookup: lookup,
		cache:  map[string]bool{},
	}
}

// counts reports whether harnessName's CostUSD should accumulate. The
// result is memoized; callers that want fresh resolution should
// construct a new tracker. Lookups for empty harness names default to
// true (count) so accidentally-missing harness metadata never silently
// bypasses the cap.
func (t *CostCapTracker) counts(harnessName string) bool {
	if harnessName == "" {
		return true
	}
	t.mu.Lock()
	if v, ok := t.cache[harnessName]; ok {
		t.mu.Unlock()
		return v
	}
	t.mu.Unlock()
	result := true
	if t.Lookup != nil {
		result = t.Lookup(harnessName)
	}
	t.mu.Lock()
	t.cache[harnessName] = result
	t.mu.Unlock()
	return result
}

// Add accumulates costUSD against the running total when harnessName's
// billing class counts toward the cap. Non-positive cost is ignored.
func (t *CostCapTracker) Add(harnessName string, costUSD float64) {
	if costUSD <= 0 {
		return
	}
	if !t.counts(harnessName) {
		return
	}
	t.mu.Lock()
	t.spent += costUSD
	t.mu.Unlock()
}

// Spent returns the current accumulated billed total.
func (t *CostCapTracker) Spent() float64 {
	t.mu.Lock()
	defer t.mu.Unlock()
	return t.spent
}

// Tripped reports whether the accumulated spend has reached MaxUSD. When
// MaxUSD <= 0 the cap is disabled and Tripped returns (_, false).
// Returns the formatted operator-facing detail string when tripped so
// callers can populate a stop-the-loop ExecuteBeadReport.
func (t *CostCapTracker) Tripped() (string, bool) {
	if t.MaxUSD <= 0 {
		return "", false
	}
	t.mu.Lock()
	spent := t.spent
	t.mu.Unlock()
	if spent < t.MaxUSD {
		return "", false
	}
	return fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, t.MaxUSD), true
}

func nextEscalationFloor(l *tierescalation.Ladder, actualPower int) (int, error) {
	if l == nil {
		return 0, tierescalation.ErrLadderExhausted
	}
	floor := actualPower
	for {
		next, err := l.Next(floor)
		if err == nil {
			return next, nil
		}
		var nvp *tierescalation.NoViableProviderError
		if errors.As(err, &nvp) {
			floor = nvp.Floor
			continue
		}
		return 0, err
	}
}

func runEscalatingSingleTierAttempts(
	ctx context.Context,
	initialMinPower int,
	ladder *tierescalation.Ladder,
	attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
	recordAttempt func(agent.ExecuteBeadReport),
) (agent.ExecuteBeadReport, error) {
	minPower := initialMinPower
	for {
		report, err := attempt(ctx, minPower)
		if recordAttempt != nil && report.BeadID != "" {
			recordAttempt(report)
		}
		if err != nil {
			return report, err
		}
		if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
			return report, nil
		}
		basis := minPower
		if report.ActualPower > 0 {
			basis = report.ActualPower
		}
		nextPower, nextErr := nextEscalationFloor(ladder, basis)
		if nextErr != nil {
			return report, nil
		}
		minPower = nextPower
	}
}

func appendTierAttemptEvent(store agent.BeadEventAppender, beadID string, report agent.ExecuteBeadReport, actor string, createdAt time.Time) {
	if store == nil || beadID == "" {
		return
	}
	body := policyescalation.FormatTierAttemptBody(report.Tier, report.Harness, report.Model, report.ProbeResult, report.Detail)
	summary := report.Status
	if report.Tier != "" {
		summary = fmt.Sprintf("%s tier=%s", summary, report.Tier)
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "tier-attempt",
		Summary:   summary,
		Body:      body,
		Actor:     actor,
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt,
	})
}

func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
	if eventSink != nil {
		defer eventSink.Close() //nolint:errcheck
	}
	store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
	rcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
		Assignee:          "ddx",
		Harness:           spec.Harness,
		Model:             spec.Model,
		Provider:          spec.Provider,
		ModelRef:          spec.ModelRef,
		Profile:           agent.NormalizeRoutingProfile(spec.Profile),
		Effort:            spec.Effort,
		OpaquePassthrough: spec.OpaquePassthrough,
	})

	var worker *agent.ExecuteBeadWorker
	var costCap *policyescalation.CostCapTracker
	if m.BeadWorkerFactory != nil {
		worker = m.BeadWorkerFactory(store)
	} else {
		// Build an executor that calls agent.ExecuteBead in-process, then
		// submits the result to the project's land coordinator. The
		// coordinator (a single goroutine per projectRoot) serializes all
		// target-ref writes for this project — this is the server-side
		// implementation of the human-PR landing model. See ddx-8746d8a6
		// for the rationale. Prior to this rewrite, runWorker never called
		// LandBeadResult at all, so commits produced by server-managed
		// workers were silently lost (ddx-e14efc58).
		coordinator := m.LandCoordinators.Get(projectRoot)

		// singleTierAttempt runs one execution at a specific harness/model.
		// The caller controls MinPower per rung; this helper keeps the
		// profile stable and only advances the power floor.
		singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
			gitOps := &agent.RealGitOps{}
			attemptProvider := spec.Provider
			if resolvedProvider != "" {
				attemptProvider = resolvedProvider
			}
			attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
				Harness:           resolvedHarness,
				Model:             resolvedModel,
				Provider:          attemptProvider,
				ModelRef:          spec.ModelRef,
				Profile:           rcfg.Profile(),
				Effort:            spec.Effort,
				MinPower:          requestedMinPower,
				OpaquePassthrough: spec.OpaquePassthrough,
			})
			beadStore := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
			res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
				BeadEvents: beadStore,
				BeadCancel: beadStore,
			}, gitOps)
			if err != nil && res == nil {
				return agent.ExecuteBeadReport{}, err
			}
			// Preserve operator-cancel results as-is; the worker has already
			// classified them (preserved / operator_cancel / preserved_needs_review)
			// and overriding here would lose the cancel signal.
			operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
			if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
				if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
					err = landErr
				}
			} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
				res.Outcome = "no-changes"
				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
			} else if res != nil && res.ExitCode != 0 && !operatorCancel {
				res.Outcome = "preserved"
				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
			}
			// Safety net: commit any leftover evidence files that Land()
			// did not pick up (e.g. HEAD was detached, or no land ran).
			if res != nil && res.AttemptID != "" {
				_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
			}
			if err != nil {
				return agent.ExecuteBeadReport{}, err
			}
			return agent.ExecuteBeadReport{
				BeadID:             res.BeadID,
				AttemptID:          res.AttemptID,
				WorkerID:           res.WorkerID,
				Harness:            res.Harness,
				Provider:           res.Provider,
				Model:              res.Model,
				ActualPower:        res.ActualPower,
				Status:             res.Status,
				Detail:             res.Detail,
				SessionID:          res.SessionID,
				BaseRev:            res.BaseRev,
				ResultRev:          res.ResultRev,
				PreserveRef:        res.PreserveRef,
				NoChangesRationale: res.NoChangesRationale,
				CostUSD:            res.CostUSD,
				DurationMS:         int64(res.DurationMS),
			}, nil
		}

		// Cost-cap state for this worker run. Subscription / local providers do
		// not contribute (see escalation.CountsTowardCostCap).
		// TODO(ddx-785d02f7): expose maxCostUSD as a worker spec field
		// once the spec config knob lands.
		var ladderOnce sync.Once
		var ladder *tierescalation.Ladder
		loadLadder := func() *tierescalation.Ladder {
			ladderOnce.Do(func() {
				ladder = tierescalation.NewLadder(nil)
				if svc, svcErr := agent.NewServiceFromWorkDir(projectRoot); svcErr == nil {
					modelFilter := agentlib.ModelFilter{}
					if harness := rcfg.Harness(); harness != "" {
						modelFilter.Harness = harness
					}
					modelCtx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
					defer cancel()
					if models, listErr := svc.ListModels(modelCtx, modelFilter); listErr == nil {
						ladder = tierescalation.NewLadder(models)
					}
				}
			})
			return ladder
		}
		costCap = policyescalation.NewCostCapTracker(policyescalation.DefaultMaxCostUSD, func(harnessName string) bool {
			svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
			if svcErr != nil {
				return true
			}
			infos, err := svc.ListHarnesses(context.Background())
			if err != nil {
				return true
			}
			for _, h := range infos {
				if h.Name == harnessName {
					return policyescalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
				}
			}
			return true
		})
		accumulateBilledCost := func(report agent.ExecuteBeadReport) {
			costCap.Add(report.Harness, report.CostUSD)
		}
		costCapTripped := func() (agent.ExecuteBeadReport, bool) {
			if _, tripped := costCap.Tripped(); !tripped {
				return agent.ExecuteBeadReport{}, false
			}
			spent := costCap.Spent()
			return agent.ExecuteBeadReport{
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, policyescalation.DefaultMaxCostUSD),
			}, true
		}
		attemptWithCostCap := func(ctx context.Context, beadID string, requestedMinPower int) (agent.ExecuteBeadReport, error) {
			if cappedReport, capped := costCapTripped(); capped {
				cappedReport.BeadID = beadID
				return cappedReport, nil
			}
			report, err := singleTierAttempt(ctx, beadID, requestedMinPower, spec.Harness, spec.Provider, spec.Model)
			if err == nil {
				accumulateBilledCost(report)
				if cappedReport, capped := costCapTripped(); capped {
					cappedReport.BeadID = beadID
					return cappedReport, nil
				}
			}
			return report, err
		}

		executor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
			attempts := make([]policyescalation.TierAttemptRecord, 0, 3)
			recordAttempt := func(report agent.ExecuteBeadReport) {
				if report.Tier == "" && report.Harness == "" && report.Model == "" && report.ProbeResult == "" && report.CostUSD == 0 && report.DurationMS == 0 {
					return
				}
				attempts = append(attempts, policyescalation.TierAttemptRecord{
					Tier:       report.Tier,
					Harness:    report.Harness,
					Model:      report.Model,
					Status:     report.Status,
					CostUSD:    report.CostUSD,
					DurationMS: report.DurationMS,
				})
				appendTierAttemptEvent(store, beadID, report, "ddx", time.Now().UTC())
			}
			report, err := runEscalatingSingleTierAttempts(ctx, rcfg.MinPower(), loadLadder(), func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
				return attemptWithCostCap(ctx, beadID, requestedMinPower)
			}, recordAttempt)
			if len(attempts) > 0 {
				winningTier := ""
				if report.Status == agent.ExecuteBeadStatusSuccess && report.Tier != "" {
					winningTier = report.Tier
				}
				_ = policyescalation.AppendEscalationSummaryEvent(store, beadID, "ddx", attempts, winningTier, time.Now().UTC())
			}
			return report, err
		})

		// Build post-merge reviewer. On-by-default unless NoReview is set in spec.
		var reviewer agent.BeadReviewer
		if !spec.NoReview {
			reviewer = &agent.DefaultBeadReviewer{
				ProjectRoot: projectRoot,
				BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
				BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
				Harness:     spec.ReviewHarness,
				Model:       spec.ReviewModel,
			}
		}

		worker = &agent.ExecuteBeadWorker{
			Store:    store,
			Executor: executor,
			Reviewer: reviewer,
		}
	}

	landingOps := agent.RealLandingGitOps{}

	loopResult, err := worker.Run(ctx, rcfg, agent.ExecuteBeadLoopRuntime{
		Once:          spec.Once,
		PollInterval:  spec.PollInterval,
		Log:           log,
		EventSink:     eventSink,
		WorkerID:      id,
		ProjectRoot:   projectRoot,
		LabelFilter:   spec.LabelFilter,
		ProgressCh:    progressCh,
		PreClaimHook:  buildPreClaimHook(projectRoot, landingOps),
		NoReview:      spec.NoReview,
		ReviewCostCap: costCap,
		WakeCh:        handle.wakeCh,

